import { Button } from 'react-native-paper';

function CustomButton({ variant = 'primary', disabled, onPress, children }) {
  const mode = variant === 'primary' ? 'contained' : 'outlined';
  return (
    <Button mode={mode} onPress={onPress} disabled={disabled}>
      {children}
    </Button>
  );
}
