```jsx
import { TextInput, HelperText } from 'react-native-paper';

function FormInput({ label, value, onChangeText, error, touched, ...props }) {
  return (
    <>
      <TextInput label={label} value={value} onChangeText={onChangeText} error={!!error && touched} {...props} />
      {touched && error && <HelperText type="error">{error}</HelperText>}
    </>
  );
}
